import{_ as e,o as d,c as o,a0 as r}from"./chunks/framework.B_6Va55p.js";const f=JSON.parse('{"title":"CLI Reference","description":"","frontmatter":{},"headers":[],"relativePath":"reference/cli.md","filePath":"reference/cli.md"}'),c={name:"reference/cli.md"};function a(s,t,n,l,i,h){return d(),o("div",null,[...t[0]||(t[0]=[r('<h1 id="cli-reference" tabindex="-1">CLI Reference <a class="header-anchor" href="#cli-reference" aria-label="Permalink to &quot;CLI Reference&quot;">​</a></h1><h2 id="tfparams" tabindex="-1"><code>tfparams</code> <a class="header-anchor" href="#tfparams" aria-label="Permalink to &quot;`tfparams`&quot;">​</a></h2><p>Generate a parameter sheet from a plan JSON and terraform-docs metadata.</p><table tabindex="0"><thead><tr><th>Flag</th><th>Default</th><th>Description</th></tr></thead><tbody><tr><td><code>--plan-json</code></td><td>stdin</td><td>Plan JSON file (<code>terraform show -json &lt;planfile&gt;</code>)</td></tr><tr><td><code>--docs-json</code></td><td>-</td><td>terraform-docs JSON, e.g. <code>&lt;(terraform-docs json .)</code> (required, repeatable)</td></tr><tr><td><code>--scope</code></td><td><code>root</code></td><td><code>root</code> (root variables) / <code>module</code> (module-passed values)</td></tr><tr><td><code>--module</code></td><td>(auto)</td><td>Module call name when <code>--scope module</code></td></tr><tr><td><code>--out</code></td><td>stdout</td><td>Output file path (overwritten if it exists)</td></tr><tr><td><code>--format</code></td><td><code>table</code></td><td><code>table</code> / <code>csv</code> / <code>json</code></td></tr><tr><td><code>--env</code></td><td>-</td><td>Environment name shown in the header</td></tr><tr><td><code>--show-sensitive</code></td><td>false</td><td>Show sensitive values unmasked</td></tr><tr><td><code>--no-default-col</code></td><td>false</td><td>Hide the Default column</td></tr><tr><td><code>--sort-by</code></td><td><code>required</code></td><td><code>required</code> (required first, then name) / <code>name</code></td></tr><tr><td><code>--recursive</code></td><td>false</td><td>Process subdirectories recursively</td></tr><tr><td><code>--recursive-path</code></td><td><code>.</code></td><td>Root to scan in recursive mode</td></tr><tr><td><code>--config</code></td><td>(search)</td><td>Config file path</td></tr></tbody></table><h2 id="tfparams-compare" tabindex="-1"><code>tfparams compare</code> <a class="header-anchor" href="#tfparams-compare" aria-label="Permalink to &quot;`tfparams compare`&quot;">​</a></h2><p>Compare applied values across environments and highlight differences.</p><table tabindex="0"><thead><tr><th>Flag</th><th>Default</th><th>Description</th></tr></thead><tbody><tr><td><code>--env</code></td><td>-</td><td><code>name=&lt;uri-or-path&gt;</code> to a plan JSON (repeat; at least two)</td></tr><tr><td><code>--docs-json</code></td><td>-</td><td>terraform-docs json file (required, repeatable)</td></tr><tr><td><code>--scope</code></td><td><code>root</code></td><td><code>root</code> / <code>module</code></td></tr><tr><td><code>--module</code></td><td>(auto)</td><td>Module call name when <code>--scope module</code></td></tr><tr><td><code>--out</code></td><td>stdout</td><td>Output file path (overwritten if it exists)</td></tr><tr><td><code>--format</code></td><td><code>table</code></td><td><code>table</code></td></tr><tr><td><code>--highlight-diff</code></td><td>true</td><td>Highlight differing rows with ⚠️</td></tr><tr><td><code>--show-sensitive</code></td><td>false</td><td>Show sensitive values unmasked</td></tr><tr><td><code>--sort-by</code></td><td><code>required</code></td><td><code>required</code> (required first, then name) / <code>name</code></td></tr></tbody></table><h2 id="env-uri-schemes" tabindex="-1"><code>--env</code> URI schemes <a class="header-anchor" href="#env-uri-schemes" aria-label="Permalink to &quot;`--env` URI schemes&quot;">​</a></h2><p>The target is each environment&#39;s <strong>plan JSON</strong>. The scheme only selects how bytes are fetched.</p><table tabindex="0"><thead><tr><th>Scheme</th><th>Backend</th><th>Example</th></tr></thead><tbody><tr><td><code>s3://</code></td><td>AWS S3</td><td><code>s3://my-bucket/env/prd/plan.json</code></td></tr><tr><td><code>gs://</code></td><td>Google Cloud Storage</td><td><code>gs://my-bucket/env/prd/plan.json</code></td></tr><tr><td><code>azblob://</code></td><td>Azure Blob Storage</td><td><code>azblob://account@container/prd/plan.json</code></td></tr><tr><td>(none)</td><td>Local file</td><td><code>./plan.json</code></td></tr></tbody></table><p>Credentials come from each cloud SDK&#39;s default credential chain. S3 region resolves from <code>AWS_REGION</code>/<code>~/.aws/config</code>; GCS project from Application Default Credentials; the Azure account from the URI or <code>AZURE_STORAGE_ACCOUNT</code>.</p>',11)])])}const u=e(c,[["render",a]]);export{f as __pageData,u as default};
